import { ShopappchatClient } from ".";

declare global {
  interface Window {
    /**
     * The Gadget client constructor
     *
     * @example
     * ```ts
     * const api = new ShopappchatClient();
     * ```
     */
    ShopappchatClient: typeof ShopappchatClient;

    /**
     * The Gadget client for ShopappchatClient
     * @deprecated Use window.ShopappchatClient instead
     */
    Gadget: typeof ShopappchatClient;
  }
}

// add the client to the window
window.ShopappchatClient = ShopappchatClient;

const previousValue: any = window.Gadget;

// add the client to the window at the old .Gadget property for backwards compatibility -- the ShopappchatClient property should be preferred instead
window.Gadget = ShopappchatClient;
(window.Gadget as any).previousValue = previousValue;
